VALUES
  ('pukao-d0d1b9a2-moex-00364', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '乙公司編製 X2 年底資產負債表時，有下列資料：銀行活期存款$85,900、員工借支$6,500、零用 金$5,500、收到客戶即期支票$10,500、旅行支票$8,000、2 個月期之定期存款$25,000、償債基金 $35,000。請問X2年底現金之餘額為？', '["$122,500", "$134,900", "$151,300", "$121,100"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00365', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司於X1年10月2日發生火災，倉庫大部分被焚毀，倉庫中存貨的殘值剩下$4,500，依毛利 法計算的火災損失為$17,500，甲公司採定期盤存制，X1年期初存貨$40,000，年初至10月2日進 貨$200,000，進貨退出及折讓$8,000，進貨運費$10,000，銷貨$284,000，銷貨運費$14,000，銷貨折 扣$20,000，試問甲公司依銷貨成本為基礎計算之毛利率為多少？', '["12%", "13.64%", "16.67%", "20%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00366', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司X1年比較財務報表顯示X1年初，現金$20,000、負債為$80,000、權益為$50,000；在X1 年間，權益增加$30,000，負債增加$20,000；在X1年底，非現金資產為$60,000。另外，甲公司在 X1年營業活動現金淨流入$200,000、投資活動現金淨流出$90,000。甲公司在X1年籌資活動之現 金流量為多少？', '["現金淨流出$70,000", "現金淨流出$130,000", "現金淨流出$10,000", "現金淨流入$210,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00367', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-110-d35177eb', 'sub-pukao-d0d1b9a2-02', NULL, 'single_choice', '甲公司淨值為正，下列那一事項會造成負債對總資產比率提高？', '["發行普通股", "發放股票股利", "處分資產發生損失", "收回公司債發生利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:04+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "415", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00001', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '下列國際法作為行政法法源之敘述，何者錯誤？', '["條約涉及人民之權利義務且具有法律上效力者，應送立法院審議", "條約與立法院制定之法律相牴觸時，應優先適用國內法律", "國際法須於條約或協定明定其內容，始可引用作為行政法法源", "經憲法法庭直接引用之國際公約，可以於授益行政的範圍內引用之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00002', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '行政程序法第5條規定：「行政行為之內容應明確」，下列敘述何者正確？', '["懲處之構成要件，法律不得以抽象概念表示", "所謂內容應該明確，僅限於行政處分", "書面行政處分書雖漏未記載處分相對人之性別，但已有足資辨別之特徵者，符合明確性原則", "行政指導無需符合明確性原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00003', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '行政機關核發甲之商場開發許可時，因甲不能提供足夠之停車位，而要求其提供金錢改善社區之照明設施， 此要求違反下列何原則？', '["比例原則", "不當聯結禁止原則", "誠信原則", "平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00004', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '行政機關應依下列何種方式行使裁量權？', '["為實現行政任務，得附加法律規定所無之條件", "為實現行政任務，得考量法律授權目的以外之因素", "應採取裁量基準所定最小干預方式，無須考量個案情節之差異", "應視個案事實情況、衡酌規範目的，進行合義務裁量"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00005', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '下列何種私經濟行為不具給付行政功能？', '["社會住宅之出租", "辦公廳舍之租用", "水電瓦斯之供應", "大眾運輸交通之經營"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('pukao-d1056197-moex-00006', 'pukao-d1056197', 'pukao-d1056197-moex-114-d1a761c9', 'sub-pukao-d1056197-01', NULL, 'single_choice', '甲縣街頭被張貼許多借款小廣告，該縣長遂下命環保機關就張貼小廣告之行為人，一律處以法定最高額之 罰鍰，若環保機關依指示裁罰，該等裁罰具有下列何種瑕疵？', '["裁量逾越", "裁量怠惰", "事實涵攝錯誤", "違反法律保留"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:47+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "412", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "僑務行政"}'::jsonb, NULL)
